/**
 * @param {number} n
 * @param {number[]} prices
 * @param {number[][]} roads
 * @return {number[]}
 */
function solve(n, prices, roads) {
    // Adjacency list to store road information
    // Each entry: [neighbor, cost_no_apple, cost_with_apple]
    const adj = Array(n).fill(0).map(() => []);

    for (const [u, v, cost, tax] of roads) {
        // Road u <-> v
        // Cost without apple: cost
        // Cost with apple: cost * tax
        const costWithApple = cost * tax;

        // Add to u's neighbors
        adj[u].push({ neighbor: v, cost_no_apple: cost, cost_with_apple: costWithApple });
        adj[v].push({ neighbor: u, cost_no_apple: cost, cost_with_apple: costWithApple });
    }

    // --- Step 1: Calculate minimum cost from any node to any other node without apples (Cost_NoApple) ---
    // This is equivalent to running Dijkstra's algorithm starting from all nodes simultaneously, 
    // but since the costs are non-negative, we can use standard Dijkstra's for all pairs if we treat it as 
    // finding shortest paths in a graph where edge weight is cost_no_apple.
    // However, since we only need min_dist(i -> j) for all i, j, running Dijkstra from every node i 
    // will give us all required shortest paths for the "empty hand" trip.

    const distNoApple = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    for (let startNode = 0; startNode < n; startNode++) {
        const distances = Array(n).fill(Infinity);
        distances[startNode] = 0;

        // Priority Queue: [distance, node]
        const pq = [[0, startNode]]; 

        while (pq.length > 0) {
            // Simple manual extraction of min (since we don't have a proper PQ implementation)
            // In a real contest, a proper binary heap would be used. Here, we simulate by sorting/finding min.
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of adj[u]) {
                const v = edge.neighbor;
                const weight = edge.cost_no_apple; // Cost without apple

                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }

        for(let j = 0; j < n; j++) {
            distNoApple[startNode][j] = distances[j];
        }
    }

    // --- Step 2: Calculate minimum cost from any node to any other node while carrying apples (Cost_WithApple) ---
    // Similarly, we need shortest paths in the graph where edge weight is cost_with_apple.

    const distWithApple = Array(n).fill(0).map(() => Array(n).fill(Infinity));

    for (let startNode = 0; startNode < n; startNode++) {
        const distances = Array(n).fill(Infinity);
        distances[startNode] = 0;

        const pq = [[0, startNode]]; 

        while (pq.length > 0) {
            pq.sort((a, b) => a[0] - b[0]);
            const [d, u] = pq.shift();

            if (d > distances[u]) continue;

            for (const edge of adj[u]) {
                const v = edge.neighbor;
                const weight = edge.cost_with_apple; // Cost with apple

                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }

        for(let j = 0; j < n; j++) {
            distWithApple[startNode][j] = distances[j];
        }
    }

    // --- Step 3: Calculate the minimum total cost for each store i ---
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let minCost = prices[i];

        // Option 2: Travel from i to j (empty hand), buy at j, travel from j back to i (carrying apples)
        // Total cost = Cost(i -> j, empty) + Price[j] + Cost(j -> i, carrying)

        for (let j = 0; j < n; j++) {
            if (i === j) continue;

            // Cost to travel i -> j (empty hand)
            const travelToCost = distNoApple[i][j];

            // Cost to travel j -> i (carrying apples)
            const travelBackCost = distWithApple[j][i];

            if (travelToCost === Infinity || travelBackCost === Infinity) {
                continue; // Cannot reach j or return to i
            }

            // Total cost for this route j:
            // Cost(i->j, empty) + Price[j] + Cost(j->i, carrying)
            const totalCost = travelToCost + prices[j] + travelBackCost;

            minCost = Math.min(minCost, totalCost);
        }

        ans[i] = minCost;
    }

    return ans;
}

