#include <vector>
#include <queue>
#include <tuple>
#include <algorithm>
#include <limits>

using namespace std;

// Define a structure/typedef for the adjacency list entry for clarity
struct Edge {
    int neighbor;
    long long cost_no_apple;
    long long cost_with_apple;
};

// Helper function for Dijkstra's algorithm
// Finds shortest paths from a single source using the specified edge weight type.
void dijkstra(int startNode, int n, const vector<vector<Edge>>& adj, 
               vector<long long>& distances, bool use_with_apple) {

    distances.assign(n, numeric_limits<long long>::max());
    distances[startNode] = 0;

    // Min-priority queue: {distance, node}
    // We use pair<long long, int> and std::priority_queue, which is a max-heap by default.
    // To simulate a min-heap, we store {-distance, node} or use greater<>.
    priority_queue<pair<long long, int>, vector<pair<long long, int>>, greater<pair<long long, int>>> pq;
    pq.push({0, startNode});

    while (!pq.empty()) {
        long long d = pq.top().first;
        int u = pq.top().second;
        pq.pop();

        if (d > distances[u]) continue;

        for (const auto& edge : adj[u]) {
            int v = edge.neighbor;
            long long weight = use_with_apple ? edge.cost_with_apple : edge.cost_no_apple;

            if (distances[u] != numeric_limits<long long>::max() && distances[u] + weight < distances[v]) {
                distances[v] = distances[u] + weight;
                pq.push({distances[v], v});
            }
        }
    }
}


std::vector<long long> solve(long long n_ll, std::vector<long long> prices, std::vector<std::vector<long long>> roads) {
    int n = (int)n_ll;

    // Adjacency list to store road information
    vector<vector<Edge>> adj(n);

    for (const auto& road : roads) {
        int u = (int)road[0];
        int v = (int)road[1];
        long long cost = road[2];
        long long tax = road[3];

        // Cost without apple: cost
        // Cost with apple: cost * tax
        long long costWithApple = cost * tax;

        // Add to u's neighbors
        adj[u].push_back({v, cost, costWithApple});
        // Add to v's neighbors (since roads are bidirectional)
        adj[v].push_back({u, cost, costWithApple});
    }

    // --- Step 1: Calculate minimum cost from any node to any other node without apples (Cost_NoApple) ---
    // distNoApple[i][j] = shortest path cost from i to j without apples
    vector<vector<long long>> distNoApple(n, vector<long long>(n));

    for (int startNode = 0; startNode < n; ++startNode) {
        vector<long long> distances;
        dijkstra(startNode, n, adj, distances, false);
        for(int j = 0; j < n; ++j) {
            distNoApple[startNode][j] = distances[j];
        }
    }

    // --- Step 2: Calculate minimum cost from any node to any other node while carrying apples (Cost_WithApple) ---
    // distWithApple[j][i] = shortest path cost from j to i carrying apples
    vector<vector<long long>> distWithApple(n, vector<long long>(n));

    for (int startNode = 0; startNode < n; ++startNode) {
        vector<long long> distances;
        dijkstra(startNode, n, adj, distances, true);
        for(int j = 0; j < n; ++j) {
            distWithApple[startNode][j] = distances[j];
        }
    }

    // --- Step 3: Calculate the minimum total cost for each store i ---
    vector<long long> ans(n);

    for (int i = 0; i < n; ++i) {
        // Option 1: Buy directly at i
        long long minCost = prices[i];

        // Option 2: Travel from i to j (empty hand), buy at j, travel from j back to i (carrying apples)
        // Total cost = Cost(i -> j, empty) + Price[j] + Cost(j -> i, carrying)

        for (int j = 0; j < n; ++j) {
            if (i == j) continue;

            // Cost to travel i -> j (empty hand)
            long long travelToCost = distNoApple[i][j];

            // Cost to travel j -> i (carrying apples)
            long long travelBackCost = distWithApple[j][i];

            if (travelToCost == numeric_limits<long long>::max() || travelBackCost == numeric_limits<long long>::max()) {
                continue; // Cannot reach j or return to i
            }

            // Total cost for this route j:
            // Cost(i->j, empty) + Price[j] + Cost(j->i, carrying)
            long long totalCost = travelToCost + prices[j] + travelBackCost;

            minCost = min(minCost, totalCost);
        }

        ans[i] = minCost;
    }

    return ans;
}

