#include <vector>
#include <queue>
#include <tuple>
#include <limits>
#include <algorithm>

using namespace std;

typedef long long ll;

// Structure to represent an edge
struct Edge {
    int neighbor;
    ll cost_no_apple;
    ll cost_with_apple;
};

// Structure for priority queue elements: {distance, node}
// We use greater<> to implement a min-heap
using PQElement = pair<ll, int>;

// Helper function to run Dijkstra's algorithm
vector<ll> dijkstra(int startNode, int n, const vector<vector<Edge>>& adj, bool use_apple_cost) {
    vector<ll> distances(n, numeric_limits<ll>::max());
    distances[startNode] = 0;

    // Min-heap priority queue: {distance, node}
    priority_queue<PQElement, vector<PQElement>, greater<PQElement>> pq;
    pq.push({0, startNode});

    while (!pq.empty()) {
        auto [d, u] = pq.top();
        pq.pop();

        if (d > distances[u]) continue;

        for (const auto& edge : adj[u]) {
            int v = edge.neighbor;
            ll weight = use_apple_cost ? edge.cost_with_apple : edge.cost_no_apple;

            if (distances[u] != numeric_limits<ll>::max() && distances[u] + weight < distances[v]) {
                distances[v] = distances[u] + weight;
                pq.push({distances[v], v});
            }
        }
    }
    return distances;
}


