                const weight = edge.cost_with_apple; // Cost with apple

                if (distances[u] + weight < distances[v]) {
                    distances[v] = distances[u] + weight;
                    pq.push([distances[v], v]);
                }
            }
        }

        for(let j = 0; j < n; j++) {
            distWithApple[startNode][j] = distances[j];
        }
    }

    // --- Step 3: Calculate the minimum total cost for each store i ---
    const ans = Array(n).fill(0);

    for (let i = 0; i < n; i++) {
        // Option 1: Buy directly at i
        let minCost = prices[i];

        // Option 2: Travel from i to j (empty hand), buy at j, travel from j back to i (carrying apples)
